const ctx = $('Code: Handle Car License Photo').first().json;
const stateRow = $input.first().json;
const state = (typeof stateRow.state === 'string') ? JSON.parse(stateRow.state) : stateRow.state;
const now = new Date();
const israelOffset = 3 * 60;
const israelTime = new Date(now.getTime() + israelOffset * 60000);
const datetimeStr = israelTime.toISOString();
return [{ json: { ...ctx, accidentPayload: { vehicle_id: state.vehicleId || ctx.sessionState?.vehicleId, datetime: state.accidentDatetime || datetimeStr, location: null, description: null, attachments: state.attachments || [] } } }];

